class Solution:
    def findLengthOfLCIS(self, nums: List[int]) -> int:
        ans=cur=1
        for i in range(1,len(nums)):
            cur=cur+1 if nums[i]>nums[i-1] else 1
            ans=max(ans,cur)
        return ans

