class Solution {
public:
    int findLengthOfLCIS(vector<int>& a) {
        int ans=1, cur=1;
        for(int i=1;i<(int)a.size();i++){
            cur = a[i]>a[i-1]?cur+1:1;
            ans=max(ans,cur);
        }
        return ans;
    }
};
